package com.auction.client.network;import com.auction.shared.model.item.ItemDTO;import com.auction.shared.model.user.UserDTO;import com.auction.shared.response.AuctionResponseDTO;/** * Lớp quản lý phiên làm việc (Session) của người dùng hiện tại ở phía Client. * * <p>Lớp sử dụng các biến {@code static} để lưu trữ thông tin người dùng xuyên suốt * vòng đời của ứng dụng JavaFX, giúp các màn hình khác nhau (như Profile, Wallet) * có thể truy xuất dữ liệu một cách tập trung mà không cần truyền tham số qua lại.</p> */public class SessionManager {  /**   * Đối tượng lưu giữ thông tin của người dùng đang đăng nhập vào hệ thống.   */  public static UserDTO currentUser;  /**   * Đối tượng lưu giữ thông tin của sản phẩm mà người dùng vừa ấn vào.   */  public static AuctionResponseDTO currentAuction;  /**   * Cập nhật thông tin người dùng hiện tại vào phiên làm việc.   */  public static void setCurrentUser(UserDTO currentUser) {    SessionManager.currentUser = currentUser;  }  /**   * Lấy thông tin người dùng đang hoạt động trong phiên làm việc.   *   * @return Đối tượng {@link UserDTO}, hoặc {@code null} nếu chưa đăng nhập   */  public static UserDTO getCurrentUser() {    return SessionManager.currentUser;  }  /**   * Xoá thông tin phiên làm việc hiện tại.   *   * <p>Được gọi khi người dùng thực hiện thao tác Đăng xuất.</p>   */  public static void clearSession() {    SessionManager.currentUser = null;  }  /**   * Cập nhật phiên đấu giá mà người dùng vừa ấn vào.   */  public static void setCurrentAuction(AuctionResponseDTO currentAuction) {    SessionManager.currentAuction = currentAuction;  }  /**   * Lấy ra phiên đấu giá hiện tại mà người dùng đang lựa chọn.   * @return Sản phẩm {@link ItemDTO}   */  public static AuctionResponseDTO getCurrentAuction() {    return SessionManager.currentAuction;  }  /**   * Xoá phiên đấu giá, được gọi khi người dùng thoát ra khỏi màn hình đấu giá hiện tại.   */  public static void clearCurrentAuction() {    SessionManager.currentAuction = null;  }}